// Extrae la recomendación directamente desde 'recommendation' o usa fallback
const rec = $input.first().json.content.parts[0].text || "Sin recomendación";

// Extraemos los datos del clima
const data = $items('Extraer datos especificos1')[0].json;

// Devolvemos todo en un solo objeto JSON, incluyendo desglose del outfit
return [{
  json: {
    city: data.city,
    temperature: data.temperature,
    feels_like: data.feels_like,
    humidity: data.humidity,
    wind: data.wind,
    condition: data.condition,
    recommendation: rec.trim(),
    outfit: data.outfit || {} // incluye top, bottom, shoes y accessories si existen
  }
}];

const current = $json.current;

const temperature = current.temperature_2m;
const humidity = current.relative_humidity_2m;
const wind = current.wind_speed_10m;
const feelsLike = current.apparent_temperature;
const code = current.weather_code;

const city = $items("Extraer coordenadas1")[0].json.city;

let condition = "Desconocido";
let recommendationText = "";
let outfit = {
  top: "",
  bottom: "",
  shoes: "",
  accessories: []
};

// Determinar la condición del clima
if (code === 0) condition = "Cielo despejado";
else if (code >= 1 && code <= 3) condition = "Parcialmente nublado";
else if (code >= 45 && code <= 48) condition = "Niebla";
else if (code >= 51 && code <= 67) condition = "Lluvia ligera";
else if (code >= 71 && code <= 77) condition = "Nieve";
else if (code >= 80 && code <= 82) condition = "Chubascos";
else if (code >= 95) condition = "Tormenta eléctrica";

// Recomendación basada en sensación térmica y clima
if (feelsLike >= 30) {
  outfit.top = "Camiseta ligera 👕";
  outfit.bottom = "Shorts 🩳";
  outfit.shoes = "Sandalias frescas 🥿";
  outfit.accessories.push("Sombrero divertido 🧢", "Gafas de sol 😎");
  recommendationText = `¡Hace calor! 🔥 Ponte camisetas ligeras y shorts cómodos, y no olvides tu sombrero o gafas de sol para brillar bajo el sol 🌞.`;
}
else if (feelsLike >= 24) {
  outfit.top = "Camiseta ligera 👕";
  outfit.bottom = "Pantalón cómodo 🩳";
  outfit.shoes = "Zapatos ligeros 👟";
  outfit.accessories.push("Sombrero 🧢", "Gafas de sol 😎");
  recommendationText = `Clima cálido y agradable 😎. Una camiseta fresca y pantalón cómodo te harán sentir genial. Sombrero y gafas de sol para el toque cool 🌞.`;
}
else if (feelsLike >= 18) {
  outfit.top = "Camiseta o camisa ligera 👕";
  outfit.bottom = "Pantalón ligero 👖";
  outfit.shoes = "Zapatos cómodos 👟";
  outfit.accessories.push("Sombrero 🧢");
  recommendationText = `¡Temperatura agradable! 🌤️ Camiseta y pantalón ligero son ideales. Añade un sombrero divertido para protegerte del sol 😎.`;
}
else if (feelsLike >= 10) {
  outfit.top = "Suéter o chaqueta ligera 🧥";
  outfit.bottom = "Pantalones largos 👖";
  outfit.shoes = "Zapatos cerrados o botas 👢";
  outfit.accessories.push("Bufanda opcional 🧣");
  recommendationText = `Hace fresquito 🧡. Ponte tu suéter o chaqueta ligera y pantalones largos para sentirte cómodo. Una bufanda opcional le da un toque acogedor 🧣.`;
}
else { // muy frío, posible nieve
  outfit.top = "Abrigo grueso o parka 🧥";
  outfit.bottom = "Pantalones térmicos o jeans gruesos 👖";
  outfit.shoes = "Botas impermeables 👢";
  outfit.accessories.push("Bufanda 🧣", "Guantes 🧤", "Gorro 🧢");
  recommendationText = `¡Hace mucho frío! ❄️ Usa abrigo grueso, pantalones térmicos y botas impermeables. No olvides bufanda, guantes y gorro para mantenerte caliente y seguro en la nieve ⛄.`;
}

// Ajustes por lluvia/chubascos
if (code >= 51 && code <= 82) {
  outfit.accessories.push("Paraguas o impermeable 🌂");
  recommendationText += " No olvides tu paraguas o impermeable, ¡no queremos sorpresas mojadas!";
}

// Ajustes por tormenta eléctrica
if (code >= 95) {
  outfit.accessories.push("Abrigo resistente a lluvia ⚡");
  recommendationText += " Mantente seguro durante la tormenta y evita lugares expuestos.";
}

// Ajustes por viento fuerte
if (wind >= 10) {
  outfit.accessories.push("Chaqueta cortavientos 💨");
  recommendationText += " Una chaqueta cortavientos puede salvarte de los empujones del viento!";
}

// Salida JSON final
return [
  {
    json: {
      city: city,
      temperature: temperature,
      humidity: humidity,
      wind: wind,
      feels_like: feelsLike,
      condition: condition,
      recommendation: recommendationText,
      outfit: outfit // desglose completo de prendas y accesorios
    }
  }
];
